SELECT t.tcm_tar_id AS tcmTarId, t.gene_entrez_id AS geneEntrezId, COALESCE(t.symbol, '') AS symbol, COALESCE(NULLIF(TRIM(t.uniprot_id), '#N/A'), NULL) AS uniprotId, COALESCE(t.ensembl_id, '') AS ensemblId, COALESCE(t.description, '') AS description, COALESCE(t.type_of_gene, '') AS typeOfGene FROM phenotype_target_rel pt INNER JOIN targets t ON pt.tcm_tar_id = t.tcm_tar_id WHERE pt.phenotype_id = #{phenotypeId}
AND (t.symbol LIKE CONCAT('%', #{keyword}, '%') OR t.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.symbol

SELECT COUNT(DISTINCT tcm_tar_id)
FROM phenotype_target_rel
WHERE phenotype_id = #{phenotypeId}
